#include <iostream>
using namespace std;

int main() {
    int a = 10;  // 1010

    cout << "a >> 1 = " << (a >> 1) << endl;  // 5
    cout << "a >> 2 = " << (a >> 2) << endl;  // 2

    // 负数右移
    int b = -10;
    cout << "b >> 1 = " << (b >> 1) << endl;  // -5

    // 快速除法
    int c = 24;
    cout << "c / 4 = " << (c >> 2) << endl;  // 6

    return 0;
}

#include <iostream>
using namespace std;

char trans(int d) {
    if (d < 10) return d + '0';
    return d - 10 + 'A';
}

int main() {
    int n, r;
    cin >> n >> r;

    string result = "";
    while (n > 0) {
        int remainder = n % r;
        result = trans(remainder) + result;
        n /= r;
    }

    cout << result << endl;
    return 0;
}
